@Component({
  selector: "app-workflow-loan-app-all-steps",
  templateUrl: "./workflow-loan-app-all-steps.page.html",
  styleUrls: ["./workflow-loan-app-all-steps.page.scss"],
  animations: [
    trigger("slideFadeIn", [
      transition(":enter", [
        style({ transform: "translateY(-20px)", opacity: 0 }), // 👈 Start above
        animate(
          "300ms ease-out",
          style({ transform: "translateY(0)", opacity: 1 }) // 👈 Move to position
        ),
      ]),
      transition(":leave", [
        animate(
          "200ms ease-in",
          style({ transform: "translateY(-20px)", opacity: 0 }) // 👈 Move back up
        ),
      ]),
    ]),
  ],
})
export class WorkflowLoanAppAllStepsPage implements OnInit {
  ApplicationPage: number;
  constructor(
    public formBuilder: FormBuilder,
    public pagingService: pagingService,
    private sortingService: sortingService,
    private LoansService: LoansService,
    private env: EnvService,
    private http: HttpClient,
    private UserService: UserService,
    private authService: MohassilAuthService,
    private LoanApplicationsService: LoanApplicationsService,
    private alertService: AlertService,
    private pdfViewerService: PdfViewerService,
    private toastController: ToastController,
    private ReferencesService: ReferencesService
  ) {}

  //region VARIABLES
  showLoader: boolean = false;
  isParametersFormValid: boolean = false;
  showDataGrid: boolean = false;
  loanTypes: LoanType[];
  users: User[];
  AppStatusRef: StaticRef[];
  workFlowLoanAppsResponsModel: workFlowLoanAppsRespons[] = [];
  workFlowLoanAppAllStepsResponsModel: workFlowLoanAppsAllStepsRespons[] = [];
  selectedAppsRowIndex: number = -1;
  selectedStepsRowIndex: number = -1;
  sortingIconParam: string;
  sortingIconClass: string = "arrow-down-outline";
  selectedLoanTypes: string;
  org_code_user_info: string;
  user_name: string;
  reportsLabels: Array<{ key: number; value: string }>;
  showReportButton: boolean = false;
  pagingObject: { pageSize: number; page: number }; // = { page: 1, pageSize: 3 };
  private currentToast: HTMLIonToastElement | null = null;
  isLoanAppStatusGenerated: boolean = false;
  @ViewChild("applicStatusList") applicStatusList: IonSelect;
  @ViewChild("ionCheckBoxSingleLoan") ionCheckBoxSingleLoan: IonCheckbox;
  isModalOpen = false;
  BranchModelResponse: IBranch[];
  isCurrStepLateWarn: boolean = false;
  client_name: string;
  nation_id: string;
  client_gender_desc: string;
  client_status_desc: string;
  app_branch_name: string;
  loan_type_name: string;
  entry_date: string;
  req_am: string;
  loan_app_actual_status: string;
  full_app_code: string;
  officer_name: string;
  is_curr_step_late: string;
  selectedLoanApps: any[] = [];
  set isAllLoanAppsSelected(value: boolean) {
    this.workFlowLoanAppsResponsModel.forEach((app) => (app.isCheck = value));
  }
  //End region

  async ngOnInit() {
    this.pagingObject = {
      pageSize: this.pagingService.getPageSizeFromLocalStorage(),
      page: 1,
    };
    this.authService.getUserInfo().then((userInfo) => {
      this.org_code_user_info = userInfo.org_code;
      this.user_name = userInfo.user_name;
    });
    this.loanTypes = await this.LoansService.getAllActiveLoanTypes();
    this.BranchModelResponse = await this.ReferencesService.GetbranchByUser();
    this.users = await this.UserService.getAllJobUsers(this.org_code_user_info);
    this.AppStatusRef =
      await this.ReferencesService.GetAppStatusRef().toPromise();
    this.reportsLabels = [
      { key: 1, value: "تفاصيل طلب القرض - الخطوة الحالية" },
    ];
  }

  //region FORMS
  parametersForm: FormGroup = this.formBuilder.group({
    start_date: [
      "",
      [
        Validators.required,
        Validators.pattern(
          "((?:19|20)\\d\\d)-(0?[1-9]|1[012])-([12][0-9]|3[01]|0?[1-9])"
        ),
        this.noDateGreaterToday,
      ],
    ],
    end_date: [
      "",
      [
        Validators.required,
        Validators.pattern(
          "((?:19|20)\\d\\d)-(0?[1-9]|1[012])-([12][0-9]|3[01]|0?[1-9])"
        ),
        this.noDateGreaterToday,
      ],
    ],
    loan_type_code: ["", Validators.required],
    // applic_status: ["", Validators.required],
    // loan_gen_status: ["", Validators.required],
    app_status_ref: ["", Validators.required],
    branch_code: ["", Validators.required],
  });
  get GetDisbursementForm() {
    return this.parametersForm.controls;
  }

  //region FORM VALIDATION
  //DONE
  noDateGreaterToday(control: FormControl) {
    const isDateGrater = new Date(control.value);
    const currentDate = new Date();
    if (isDateGrater > currentDate) {
      return { DateIsGrater: true };
    }
  }

  //region FORM TOOLS
  //DONE
  loanAppStatusOnChange() {
    if (this.applicStatusList.value == 1) {
      this.isLoanAppStatusGenerated = true;

      this.parametersForm.controls.loan_gen_status.setValidators([]);
      this.parametersForm.controls.loan_gen_status.addValidators(
        Validators.required
      );
      this.parametersForm.controls.loan_gen_status.updateValueAndValidity();
    } else {
      this.parametersForm.patchValue({
        loan_gen_status: 0,
      });
      this.isLoanAppStatusGenerated = false;
      this.parametersForm.controls.loan_gen_status.setValidators([]);
      this.parametersForm.controls.loan_gen_status.removeValidators(
        Validators.required
      );
      this.parametersForm.controls.loan_gen_status.updateValueAndValidity();
    }
  }

  //DONE
  clear() {
    this.workFlowLoanAppsResponsModel = [];
    this.selectedLoanTypes = "";
    this.showReportButton = false;
    this.pagingObject.page = 1;
    this.showDataGrid = false;
    this.selectedAppsRowIndex = -1;
    this.selectedStepsRowIndex = -1;
    this.selectedLoanApps = [];
  }

  //DONE
  selectAppsGridRow(index: number) {
    this.selectedAppsRowIndex = index;
  }

  selectStepsGridRow(index: number) {
    this.selectedStepsRowIndex = index;
  }

  //DONE
  getRowClassesStepsGrid(
    expiry_date: string,
    date_finished: string,
    index: number
  ): string[] {
    const today = new Date();
    const expiryDate = new Date(expiry_date);
    const isLate = expiryDate < today && date_finished == null;
    const isSelected = this.selectedStepsRowIndex === index;

    if (isLate && isSelected) return ["late-selected"];
    if (isLate) return ["late-date"];
    if (isSelected) return ["highlighted-row"];
    if (expiryDate < today) {
      this.is_curr_step_late = "متأخر";
      this.isCurrStepLateWarn = true;
    } else {
      this.is_curr_step_late = "غير متأخر";
      this.isCurrStepLateWarn = false;
    }
    return [];
  }

  //DONE
  getRowClassesAppsGrid(expiry_date: string, index: number): string[] {
    const today = new Date();
    const expiryDate = new Date(expiry_date);
    const isLate = expiryDate < today && expiry_date != null;
    const isSelected = this.selectedAppsRowIndex === index;

    if (isLate && isSelected) return ["late-selected"];
    if (isLate) return ["late-date"];
    if (isSelected) return ["highlighted-row"];
    return [];
  }

  //DONE
  sortingTable(data: any, param: string) {
    this.sortingService.sortByParameter(data, param);
    this.sortingIconClass =
      this.sortingService.sortOrder === "asc"
        ? "arrow-down-outline"
        : "arrow-up-outline";
    this.sortingIconParam = param;
  }

  //DONE
  changePaginationPage = (newPage: number): void => {
    this.pagingObject.page = newPage;
    this.selectedAppsRowIndex = -1;
    this.selectedStepsRowIndex = -1;
  };

  //region DATA GETTERS
  //DONE
  async getWfLoanApps() {
    this.isParametersFormValid = true;
    if (
      this.parametersForm.controls.end_date.value <
      this.parametersForm.controls.start_date.value
    ) {
      this.alertService.showAlertError(
        "لا يمكن اختيار تاريخ النهاية اصغر من تاريخ البداية",
        null
      );
    } else if (this.parametersForm.valid) {
      this.showLoader = true;
      this.clear();
      this.collectParamsStrings();

      this.workFlowLoanAppsResponsModel =
        await this.LoanApplicationsService.getWfAllLoansApps(
          this.parametersForm.controls.start_date.value,
          this.parametersForm.controls.end_date.value,
          this.parametersForm.controls.loan_type_code.value,
          this.parametersForm.controls.branch_code.value,
          this.parametersForm.controls.app_status_ref.value
        );
      if (this.workFlowLoanAppsResponsModel.length != 0) {
        this.showDataGrid = true;
      } else {
        this.alertService.showAlertError(
          "لا يوجد نتيجة بناء على الخصائص المختارة",
          null
        );
      }
      this.showLoader = false;
    }
  }

  //DONE
  async getAllAppSteps(application_key: number) {
    this.selectedLoanApps = [];
    this.selectedLoanApps.push(application_key);
    if (application_key) {
      this.showLoader = true;
      this.workFlowLoanAppAllStepsResponsModel =
        await this.LoanApplicationsService.getAllAppSteps(application_key);
      this.showLoader = false;
      this.setOpen(true);
    }
    this.client_name =
      this.workFlowLoanAppAllStepsResponsModel[0]["client_name"];
    this.nation_id = this.workFlowLoanAppAllStepsResponsModel[0]["nation_id"];
    this.client_gender_desc =
      this.workFlowLoanAppAllStepsResponsModel[0]["client_gender_desc"];
    this.client_status_desc =
      this.workFlowLoanAppAllStepsResponsModel[0]["client_status_desc"];

    this.app_branch_name =
      this.workFlowLoanAppAllStepsResponsModel[0]["app_branch_name"];

    this.loan_type_name =
      this.workFlowLoanAppAllStepsResponsModel[0]["loan_type_name"];

    this.entry_date = this.workFlowLoanAppAllStepsResponsModel[0]["entry_date"];
    this.req_am = this.workFlowLoanAppAllStepsResponsModel[0]["req_am"];

    this.loan_app_actual_status =
      this.workFlowLoanAppAllStepsResponsModel[0]["loan_app_actual_status"];

    this.full_app_code =
      this.workFlowLoanAppAllStepsResponsModel[0]["application_code"] +
      " / " +
      this.workFlowLoanAppAllStepsResponsModel[0]["client_code"] +
      " / " +
      this.workFlowLoanAppAllStepsResponsModel[0]["branch_code"];

    this.officer_name =
      this.workFlowLoanAppAllStepsResponsModel[0]["officer_name"];
  }

  //region FORM ACTIONS
  //DONE
  collectParamsStrings() {
    this.selectedLoanTypes =
      this.parametersForm.controls.loan_type_code.value.join(`,`);
  }

  //region GET REPORT
  private b64DecodeUnicode(str): string {
    return decodeURIComponent(
      atobSafe(str)
        .split("")
        .map(function (c) {
          return "%" + ("00" + c.charCodeAt(0).toString(16)).slice(-2);
        })
        .join("")
    );
  }

  public async getReport(Report: string) {
    let ReportValue = Report;
    if (ReportValue == "" || !!!ReportValue) {
      this.alertService.showAlertError("يجب اختيار نوع تقرير", false, "موافق");
    } else {
      let reportName: string;
      let reportParameter: Array<{ key: string; value: string }> = [];
      switch (ReportValue) {
        case "1":
          if (this.selectedLoanApps.length != 0) {
            if (this.sortingIconParam == undefined) {
              this.sortingIconParam = "row_num";
            }
            reportName = "workflow_all_loan_apps_by_app_key";
            reportParameter = [
              {
                key: "@start_date",
                value: this.parametersForm.controls.start_date.value,
              },
              {
                key: "@end_date",
                value: this.parametersForm.controls.end_date.value,
              },
              { key: "@loan_type_code", value: this.selectedLoanTypes },
              {
                key: "@application_key",
                value: this.selectedLoanApps.toString(),
              },
              {
                key: "@sorting_col_order",
                value: this.sortingIconParam.toString(),
              },
              {
                key: "@order_dir",
                value: this.sortingService.sortOrder.toString(),
              },
            ];
          } else {
            this.alertService.showAlertError(
              "يجب اختيار طلبات قروض للعرض",
              false
            );
          }
          break;
        case "2":
          if (this.selectedLoanApps.length != 0) {
            reportName = "workflow_loan_app_all_steps";
            reportParameter = [
              {
                key: "@application_key",
                value: this.selectedLoanApps.toString(),
              },
            ];
          } else {
            this.alertService.showAlertError(
              "يجب اختيار طلبات قروض للعرض",
              false
            );
          }
          break;
      }
      let token = await this.authService.getAccessToken();
      token = token.replace("-", "+").replace("_", "/");
      const claims = JSON.parse(atobSafe(token.split(".")[1]));
      let username: string = "";
      let pwd: string = "";
      try {
        username = this.b64DecodeUnicode(btoa(claims.user_name));
      } catch (err) {
        username = claims.user_name;
      }
      try {
        pwd = this.b64DecodeUnicode(btoa(claims.pwd));
      } catch (err) {
        pwd = claims.pwd;
      }
      this.showLoader = true;
      this.http
        .post<Report>(this.env.API_URL + `api/Reporting/GetReport`, {
          report_name: reportName,
          report_parameters: reportParameter,
          token: {
            username: username,
            password: pwd,
          },
        })
        .subscribe({
          next: async (data) => {
            this.showLoader = false;
            if (data.status_code == 200) {
              this.showClientReportPdf(data.report!, null);
            } else {
              await this.alertService.showAlertError(data.message, false);
            }
          },
          error: async (err) => {
            await this.alertService.showAlertError(err.error, false);
            this.showLoader = false;
          },
        });
    }
  }

  public async showClientReportPdf(pdfBase64: string, client_name: string) {
    if (!this.pdfViewerService.canViewPdf()) {
      await this.alertService.showAlertError(
        "لا يمكن عرض أو تنزيل المستند على المتصفح الحالي",
        false
      );
      return;
    }
    let reportlabel = this.reportsLabels.find(
      (x) => x.key == 1 //this.ReportForm.controls.reportValue.value
    ).value;
    await this.pdfViewerService.viewPdf(
      pdfBase64!,
      `تقرير ${{ reportlabel }} - ${{ client_name }}.pdf`,
      reportlabel
    );
  }

  // region TOAST
  async presentToast(opts: ToastOptions) {
    if (this.currentToast) {
      await this.currentToast.dismiss();
    }

    this.currentToast = await this.toastController.create({
      ...opts,
      cssClass: "custom-toast",
    });

    setTimeout(() => {
      document.addEventListener("click", this.handleGlobalClick, {
        once: true,
      });
    });

    this.currentToast.onDidDismiss().then(() => {
      this.currentToast = null;
      document.removeEventListener("click", this.handleGlobalClick);
    });

    await this.currentToast.present();
  }

  private handleGlobalClick = async () => {
    if (this.currentToast) {
      await this.currentToast.dismiss();
      this.currentToast = null;
    }
  };

  async presentStackedToast(
    docSuspendedNotes: string,
    clientName: string,
    docSuspendedTill: string
  ) {
    let formateddocSuspendedTill = format(
      new Date(docSuspendedTill),
      "dd-MM-yyyy"
    );
    await this.presentToast({
      header:
        "اسم العميل: " +
        clientName +
        "  |  " +
        "موقوف مؤقت حتي تاريخ: " +
        formateddocSuspendedTill,
      message: "ملاحظات الايقاف المؤقت: " + docSuspendedNotes,
      buttons: [{ text: "إغلاق" }],
      keyboardClose: true,
      layout: "stacked",
      icon: "newspaper",
    });
  }

  // region CHECK BOX
  onCheckboxMasterChange(event: any) {
    const isChecked = event.target.checked;
    this.workFlowLoanAppsResponsModel.forEach(
      (app) => (app.isCheck = isChecked)
    );
    this.updateSelectedLoanForAll(isChecked);
  }

  updateSelectedLoanForAll(isChecked: boolean) {
    this.selectedLoanApps = [];
    if (isChecked) {
      this.workFlowLoanAppsResponsModel.forEach((app) => {
        this.selectedLoanApps.push(app.application_key);
      });
    }
  }

  onCheckboxChange(event: any, loan_key: any, index: any) {
    const selectedLoan =
      this.workFlowLoanAppsResponsModel[
        index + this.pagingObject.pageSize * (this.pagingObject.page - 1)
      ];
    selectedLoan.isCheck = event.target.checked;
    this.updateSelectedLoan(loan_key, event.target.checked);
    this.updateMasterSingleLoanCheckbox();
    if (
      this.workFlowLoanAppsResponsModel.length !== this.selectedLoanApps.length
    ) {
      this.ionCheckBoxSingleLoan.indeterminate = true;
    } else if (
      this.workFlowLoanAppsResponsModel.length == this.selectedLoanApps.length
    ) {
      this.ionCheckBoxSingleLoan.indeterminate = false;
      this.ionCheckBoxSingleLoan.checked = true;
    }
    if (this.selectedLoanApps.length == 0) {
      this.ionCheckBoxSingleLoan.indeterminate = false;
      this.showReportButton = false;
    } else {
      this.showReportButton = true;
    }
  }

  updateSelectedLoan(loan_key: any, isChecked: boolean) {
    const index = this.selectedLoanApps.indexOf(loan_key);
    if (isChecked && index === -1) {
      this.selectedLoanApps.push(loan_key);
    } else if (!isChecked && index > -1) {
      this.selectedLoanApps.splice(index, 1);
    }
  }

  updateMasterSingleLoanCheckbox() {
    const allSelected = this.workFlowLoanAppsResponsModel.every(
      (loan) => loan.isCheck
    );
    const someSelected = this.workFlowLoanAppsResponsModel.some(
      (loan) => loan.isCheck
    );

    if (allSelected) {
      this.isAllLoanAppsSelected = true;
    } else if (!someSelected) {
      this.ionCheckBoxSingleLoan.checked = false;
      this.ionCheckBoxSingleLoan.indeterminate = false;
      this.isAllLoanAppsSelected = false;
    }
  }

  //region ALL STEPS MODAL
  setOpen(isOpen: boolean) {
    this.isModalOpen = isOpen;
    this.clearStepsModal();
  }

  clearStepsModal() {
    if (this.isModalOpen == false) {
      this.client_name = "";
      this.nation_id = "";
      this.client_gender_desc = "";
      this.client_status_desc = "";
      this.workFlowLoanAppAllStepsResponsModel = [];
      this.selectedStepsRowIndex = -1;
      this.selectedLoanApps = [];
      this.isAllLoanAppsSelected = false;
    }
  }
}
